jest.mock("fluent-ffmpeg");
import ffmpeg from "fluent-ffmpeg";
var  { completeAkashicAudio } = require("../lib/completeAkashicAudio");
const isWindows = process.platform === "win32"

describe("ffmpeg", () => {
	it("sourcePath", () => {
		const ffmpegPath = "/hoge/fuga/bin/ffmpeg";
		const receivedFfmpegPath: string[] = [];
		(ffmpeg as any).mockReturnValue({
			setFfmpegPath: (path: string) => {
				receivedFfmpegPath.push(path);
			},
			getAvailableCodecs: () => {}
		});
		completeAkashicAudio({
			sourcePaths: [],
			overwrite: "force",
			ffmpegPath
		});
		expect(receivedFfmpegPath).toEqual([ffmpegPath]);
	});
});

describe("FfmpegCommand", () => {
	let ffmpegMockImpl: any;
	let expectFuncs: any = {};
	beforeEach(function() {
		ffmpegMockImpl = {
			getAvailableCodecs: (cb: any) => {
				cb(undefined, {
					libvorbis: {
						type: 'audio',
						description: 'Vorbis (decoders: vorbis libvorbis ) (encoders: vorbis libvorbis )',
						intraFrameOnly: true,
						isLossy: true,
						isLossless: false,
						canEncode: true,
						canDecode: true
					  }
				});
			},
			output: (destPath: string) => {
				if (expectFuncs.output) expectFuncs.output(destPath);
				return ffmpegMockImpl;
			},
			addOption: (options: string[]) => {
				if (expectFuncs.addOption) expectFuncs.addOption(options);
			},
			on: (event: string, cb: any) => {
				cb();
				return ffmpegMockImpl;
			}
		};
		(ffmpeg as any).mockReturnValue(ffmpegMockImpl);
	});
	afterEach(function() {
		expectFuncs = {};
	});

	describe("convert", () => {
		it("OGGtoAAC", async () => {
			const receivedOutputs: string[] = [];
			const receivedOptions: string[] = [];
			expectFuncs.output = (destPath: string) => {
				receivedOutputs.push(destPath);
			};
			expectFuncs.addOption = (options: string) => {
				receivedOptions.push(options);
			}
			await completeAkashicAudio({
				sourcePaths: ["foo.ogg"],
				overwrite: "force"
			});
			expect(receivedOutputs).toEqual(["foo.aac"]);
			expect(receivedOptions).toEqual(["-map a", "-strict 2"]);
		});

		it("OGGtoM4A", async () => {
			const receivedOutputs: string[] = [];
			const receivedOptions: string[] = [];
			expectFuncs.output = (destPath: string) => {
				receivedOutputs.push(destPath);
			};
			expectFuncs.addOption = (options: string) => {
				receivedOptions.push(options);
			}
			await completeAkashicAudio({
				sourcePaths: ["foo.ogg"],
				overwrite: "force",
				outputM4a: true
			});
			expect(receivedOutputs).toEqual(["foo.m4a"]);
			expect(receivedOptions).toEqual(["-map a", "-strict 2"]);
		});

		it("AACToOGG", async () => {
			const receivedOutputs: string[] = [];
			const receivedOptions: string[] = [];
			expectFuncs.output = (destPath: string) => {
				receivedOutputs.push(destPath);
			};
			expectFuncs.addOption = (options: string) => {
				receivedOptions.push(options);
			}
			await completeAkashicAudio({
				sourcePaths: ["foo.aac"],
				overwrite: "force"
			});
			expect(receivedOutputs).toEqual(["foo.ogg"]);
			expect(receivedOptions).toEqual(["-map a", "-acodec libvorbis"]);
		});

		it("toOGGAndAAC", async () => {
			const receivedOutputs: string[] = [];
			const receivedOptions: string[] = [];
			expectFuncs.output = (destPath: string) => {
				receivedOutputs.push(destPath);
			};
			expectFuncs.addOption = (options: string) => {
				receivedOptions.push(options);
			}
			await completeAkashicAudio({
				sourcePaths: ["foo.wav"],
				overwrite: "force"
			});
			expect(receivedOutputs).toEqual(["foo.aac", "foo.ogg"]);
			expect(receivedOptions).toEqual(["-map a", "-strict 2", "-map a", "-acodec libvorbis"]);
		});

		it("toOGGAndM4A", async () => {
			const receivedOutputs: string[] = [];
			const receivedOptions: string[] = [];
			expectFuncs.output = (destPath: string) => {
				receivedOutputs.push(destPath);
			};
			expectFuncs.addOption = (options: string) => {
				receivedOptions.push(options);
			}
			await completeAkashicAudio({
				sourcePaths: ["foo.wav"],
				overwrite: "force",
				outputM4a: true
			});
			expect(receivedOutputs).toEqual(["foo.m4a", "foo.ogg"]);
			expect(receivedOptions).toEqual(["-map a", "-strict 2", "-map a", "-acodec libvorbis"]);
		});

	});

	describe("output option", () => {
		it ("no output option", async() => { 
			const receivedOutputs: string[] = [];
			expectFuncs.output = (destPath: string) => {
				if (isWindows) { 
					destPath = destPath.replace(/\\/g, "/");
				}
				receivedOutputs.push(destPath);
			};

			await completeAkashicAudio({
				sourcePaths: ["foo/foo1.ogg","foo/foo2.ogg", "hoge/hoge.ogg"],
				overwrite: "force",
				outputM4a: true
			});
			expect(receivedOutputs).toEqual(["foo/foo1.m4a", "foo/foo2.m4a", "hoge/hoge.m4a"]);
		});

		it ("specify file path", async() => { 
			try { 
				await completeAkashicAudio({
					sourcePaths: ["foo.ogg"],
					outputPath: "./hogeDir/hoge.m4a",
					overwrite: "force",
					outputM4a: true
				});
			} catch (e) {
				expect(e.message).toBe("Invalid -o option value, Please specify the directory path.")
			}
		});

		it ("specify directory path", async() => { 
			let receivedOutputs: string[] = [];
			expectFuncs.output = (destPath: string) => {
				if (isWindows) { 
					destPath = destPath.replace(/\\/g, "/");
				}
				receivedOutputs.push(destPath);
			};
			await completeAkashicAudio({
				sourcePaths: ["foo/foo1.ogg","foo/foo2.ogg", "hoge/hoge.ogg"],
				outputPath: "audio/out",
				overwrite: "force",
				outputM4a: true
			});
			expect(receivedOutputs).toEqual(["audio/out/foo1.m4a", "audio/out/foo2.m4a", "audio/out/hoge.m4a"]);

			receivedOutputs = [];
			await completeAkashicAudio({
				sourcePaths: ["foo/foo1.ogg", "hoge/hoge.ogg"],
				outputPath: ".",
				overwrite: "force",
				outputM4a: true
			});
			expect(receivedOutputs).toEqual(["foo1.m4a", "hoge.m4a"]);

		});
	});
});

import * as fs from "fs";
import * as path from "path";
import { Command } from "commander";
import { completeAkashicAudio } from "./completeAkashicAudio";

const commander = new Command();

var ver = JSON.parse(fs.readFileSync(path.resolve(__dirname, "..", "package.json"), "utf8")).version;
commander
	.version(ver)
	.usage("<filepath> <options>")
	.option("-o, --output <path>", "出力先ディレクトリを指定する。省略時は <filepath> と同じディレクトリに出力")
	.option("-f, --force", "出力ファイルが既に存在する場合、上書きする")
	.option("-i, --ignore", "出力ファイルが既に存在する場合、何もしない")
	.option("--ffmpeg <path>", "ffmpegのバイナリのフルパスを直接指定する場合に使うオプション")
	.option("-b, --bitrate <bitrate>", "出力する音声のビットレート。FFmpegの-abオプションに相当（experimental）")
	.option("-c, --channels <channels>", "出力する音声のチャンネル数。FFmpegの-acオプションに相当")
	.option("-r, --rate <rate>", "出力する音声のサンプリングレート。FFmpegの-arオプションに相当")
	.option("--output-aac", "m4aファイルのかわりにaacファイルを出力する")
	.option("--experimental-output-m4a", "非推奨 (現在はこの値に関わらずm4aを出力する)")
	.option("--ogg-serial-offset <number>", "Oggのlogical bitstreamのシリアルナンバーを指定する");

async function cli(): Promise<void> {
	const options = commander.opts();
	const output: string = options.output;
	const force: string = options.force;
	const ignore: string = options.ignore;
	const ffmpeg: string = options.ffmpeg;
	const bitrate: string = options.bitrate;
	const channels: string = options.channels;
	const rate: string = options.rate;
	const outputAac = options.outputAac;
	const oggOption = {
		serialOffset: options.oggSerialOffset,
	};
	if (force && ignore) {
		console.log("You can not provide force and ignore at the same time");
		process.exit(1);
	}
	await completeAkashicAudio({
		sourcePaths: commander.args,
		outputPath: output,
		overwrite: force ? "force" : (ignore ? "ignore" : "question"),
		ffmpegPath: ffmpeg,
		outputM4a: !outputAac,
		options: { bitrate, channels, rate, oggOption },
	});
	console.log("done!");
	process.exit(0);
}

export function run(argv: string[]): void {
	if (argv.length < 3) {
		commander.help();
	}
	commander.parse(argv);
	cli();
}

import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";
import ffmpeg from "fluent-ffmpeg";

export type OverwriteType = "force" | "question" | "ignore";
export const BUILTIN_AAC_ENCODER = "<builtin-aac>";

export interface OggOption {
	serialOffset?: string;
}

export interface FfmpegOption {
	bitrate?: string;
	channels?: string;
	rate?: string;
	oggOption?: OggOption;
}

export interface CompleteAkashicAudioParameterObject {
	sourcePaths: string[];
	outputPath: string | undefined;
	overwrite: OverwriteType;
	ffmpegPath?: string;
	aacCodecNames?: string[];
	oggCodecNames?: string[];
	outputM4a?: boolean;
	options?: FfmpegOption;
}

export async function completeAkashicAudio(param: CompleteAkashicAudioParameterObject): Promise<void> {
	const {
		sourcePaths,
		outputPath,
		overwrite,
		ffmpegPath,
		aacCodecNames = ["libfaac", "libvo_aacenc"],
		oggCodecNames = ["libvorbis"],
		options = {},
		outputM4a,
	} = param;

	if (outputPath) {
		if (path.extname(outputPath) !== "" ) {
			throw new Error("Invalid -o option value, Please specify the directory path.");
		}
		fs.mkdirSync(outputPath, { recursive: true });
	}

	const availableCodecs = await getAvailableCodecs(ffmpegPath);
	const aacCodecName = aacCodecNames.find(name => !!availableCodecs[name]) ?? BUILTIN_AAC_ENCODER;
	const oggCodecName = oggCodecNames.find(name => !!availableCodecs[name]);
	const aacOptions: FfmpegOption = { ...options, oggOption: undefined };
	const oggOptions: FfmpegOption = { ...options };
	if (!oggCodecName) {
		if (sourcePaths.some(p => path.extname(p) !== ".ogg")) {
			throw new Error(
				`No available codec in ${JSON.stringify(oggCodecNames)}.` +
				"You need to rebuild ffmpeg with approprite options (e.g. --enable-libvorbis) " +
				"or to reinstall ffmpeg with appropriate libraries (e.g. libvorbis)."
			);
		}
	}

	for (let i = 0; i < sourcePaths.length; ++i) {
		const sourcePath = sourcePaths[i];
		const srcExt = path.extname(sourcePath);
		if (srcExt === "")
			throw new Error(`The input ${sourcePath} must have a file extension`);
		if (!/^\.(wav|ogg|aac|mp3|mp4|m4a)$/.test(srcExt)) {
			console.warn(
				`Unknown file type: ${srcExt}. ` +
				"complete-audio does not officially support this type and may cause error."
			);
		}

		const ext = outputM4a ? ".m4a" : ".aac";
		const destDir = outputPath || path.dirname(sourcePath);
		if (srcExt !== ext) {
			const fileName = path.basename(sourcePath, srcExt) + ext;
			const destPath = path.join(destDir, fileName);
			await convert({ sourcePath, destPath, codecName: aacCodecName, overwrite, options: aacOptions, ffmpegPath });
		}
		if (srcExt !== ".ogg") {
			const fileName = path.basename(sourcePath, srcExt) + ".ogg";
			const destPath = path.join(destDir, fileName);
			await convert({ sourcePath, destPath, codecName: oggCodecName, overwrite, options: oggOptions, ffmpegPath });
		}
	}
}

interface ConvertParameterObject {
	sourcePath: string;
	destPath: string;
	/// 利用するコーデック名、または組み込みのAACエンコーダを使うための `"<builtin-aac>"`
	codecName: string;
	overwrite: OverwriteType;
	options: FfmpegOption;
	ffmpegPath?: string;
}

async function convert(param: ConvertParameterObject): Promise<void> {
	const { sourcePath, destPath, codecName, overwrite, options, ffmpegPath } = param;

	// 上書きチェック
	if (overwrite !== "force" && fs.existsSync(destPath)) {
		if (overwrite === "ignore" || (overwrite === "question" && !(await askOverwrite(destPath))))
			return;
	}

	const ffmpegCmd = ffmpeg(sourcePath);
	ffmpegCmd.addOption("-map a");
	if (ffmpegPath)
		ffmpegCmd.setFfmpegPath(ffmpegPath);

	if (codecName !== BUILTIN_AAC_ENCODER)
		ffmpegCmd.addOption("-acodec " + codecName);

	// TODO 必要性確認 (2015-12-05 までビルトインの AAC エンコードに -strict -2 が必要だった名残？ (のしかも値がおかしいもの？))
	// ref. https://trac.ffmpeg.org/wiki/Encode/AAC?action=diff&version=40&old_version=39
	if (codecName === BUILTIN_AAC_ENCODER)
		ffmpegCmd.addOption("-strict 2");

	if (!!options.bitrate)
		ffmpegCmd.addOption("-ab " + options.bitrate);
	if (!!options.channels)
		ffmpegCmd.addOption("-ac " + options.channels);
	if (!!options.rate)
		ffmpegCmd.addOption("-ar " + options.rate);
	if (!!options.oggOption?.serialOffset) {
		ffmpegCmd.addOption("-bitexact");
		ffmpegCmd.addOption("-serial_offset " + options.oggOption?.serialOffset);
	}

	return new Promise((resolve, reject) => {
		ffmpegCmd.output(destPath)
			.on("end", () => {
				console.log("write " + destPath);
				resolve();
			})
			.on("error", (err: any, stdout: string, stderr: string) => {
				// TODO error を投げるようにする
				reject("ffmpeg stdout:\n" + stdout + "\nffmpeg stderr:\n" + stderr + "\n" + err);
			});
		ffmpegCmd.run();
	});
}

function getAvailableCodecs(ffmpegPath: string | undefined): Promise<ffmpeg.Codecs> {
	return new Promise((resolve, reject) => {
		const ffmpegCmd = ffmpeg();
		if (ffmpegPath)
			ffmpegCmd.setFfmpegPath(ffmpegPath);
		ffmpegCmd.getAvailableCodecs((err: any, codecs: ffmpeg.Codecs) => {
			return err ? void reject(err) : resolve(codecs);
		});
	});
}

function askOverwrite(dest: string): Promise<boolean> {
	return new Promise((resolve, _reject) => {
		const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
		rl.question("Do you want to overwrite " + dest + " ? y/N : ", (value: string) => {
			rl.close();
			resolve(value === "y");
		});
	});
}
